const body = $input.first().json;

const topic  = body.topic  || body.query || body.message || '';
const domain = body.domain || 'general';
const level  = body.level  || 'PhD';
const userId = body.userId || 'anonymous';
const path   = body.routePath || 'research';

if (!topic || topic.trim().length < 5) {
  return [{
    json: {
      success:   false,
      error:     'Topic must be at least 5 characters.',
      routePath: path
    }
  }];
}

// Only run needed agents based on path
const runAllAgents    = path === 'research';
const runAdvisorOnly  = path === 'advisor';
const runChatOnly     = path === 'chat';

return [{
  json: {
    topic:         topic.trim(),
    domain:        domain.trim(),
    level,
    userId,
    routePath:     path,
    runAllAgents,
    runAdvisorOnly,
    runChatOnly,
    timestamp:     new Date().toISOString(),
    requestId:    `req_${Date.now()}`
  }
}];

const output = $input.first().json.output || 
               $input.first().json?.choices?.[0]?.message?.content || 
               'No response from Research Scout';

return [{
  json: {
    agent: 'Agent 1 — Research Scout',
    role: 'Literature landscape & research gaps',
    output: output,
    timestamp: new Date().toISOString()
  }
}];

const output = $input.first().json.output || 
               $input.first().json?.choices?.[0]?.message?.content || 
               'No response from Topic Advisor';

return [{
  json: {
    agent:     'Agent 2 — Topic Advisor',
    role:      'Refined topic options with feasibility scores',
    output:    output,
    timestamp: new Date().toISOString()
  }
}];

const output = $input.first().json.output || 
               $input.first().json?.choices?.[0]?.message?.content || 
               'No response from AI Assistant';

return [{
  json: {
    agent:     'Agent 3 — AI Assistant',
    role:      'Career relevance & usefulness insights',
    output:    output,
    timestamp: new Date().toISOString()
  }
}];

const input = $input.first().json;

// For sequential flow — all data comes through Agent 3
const agent1Output = input.agent1Output || input.output || '';
const agent2Output = input.agent2Output || input.output || '';
const agent3Output = input.output || '';

return [{
  json: {
    success:   true,
    requestId: input.requestId || `req_${Date.now()}`,
    timestamp: new Date().toISOString(),
    topic:     input.topic     || '',
    domain:    input.domain    || '',
    agents: {
      researchScout: {
        agent:  'Agent 1 — Research Scout',
        role:   'Literature landscape & research gaps',
        output: agent1Output
      },
      topicAdvisor: {
        agent:  'Agent 2 — Topic Advisor',
        role:   'Refined topic options with feasibility scores',
        output: agent2Output
      },
      aiAssistant: {
        agent:  'Agent 3 — AI Assistant',
        role:   'Career relevance & usefulness insights',
        output: agent3Output
      }
    },
    disclaimer: 'Verify all outputs with primary academic sources.'
  }
}];

const body = $input.first().json;
const email    = body.email    || '';
const password = body.password || '';

if (!email || !password) {
  return [{
    json: {
      success: false,
      error: 'Email and password are required'
    }
  }];
}

if (!email.includes('@')) {
  return [{
    json: {
      success: false,
      error: 'Invalid email format'
    }
  }];
}

if (password.length < 6) {
  return [{
    json: {
      success: false,
      error: 'Password must be at least 6 characters'
    }
  }];
}

const userId = Buffer.from(email).toString('base64');
const token  = `jwt_${userId}_${Date.now()}`;

return [{
  json: {
    success: true,
    token,
    refreshToken: `refresh_${userId}_${Date.now()}`,
    expiresIn: 86400,
    user: {
      id:     userId,
      name:   email.split('@')[0],
      email:  email,
      avatar: null,
      plan:   'free'
    }
  }
}];

const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};
const path = body.path || 
             headers['x-request-path'] || 
             'research';

const cleanPath = path.replace('/', '').trim();

return [{
  json: {
    ...body,
    routePath:  cleanPath,
    isLogin:    cleanPath === 'login',
    isSignup:   cleanPath === 'signup',
    isResearch: cleanPath === 'research',
    timestamp:  new Date().toISOString()
  }
}];

const body = $input.first().json;
const name     = body.name     || '';
const email    = body.email    || '';
const password = body.password || '';

if (!name || !email || !password) {
  return [{
    json: { success: false, error: 'Name, email and password are required' }
  }];
}

if (!email.includes('@')) {
  return [{
    json: { success: false, error: 'Invalid email format' }
  }];
}

if (password.length < 6) {
  return [{
    json: { success: false, error: 'Password must be at least 6 characters' }
  }];
}

const userId = Buffer.from(email).toString('base64');
const token  = `jwt_${userId}_${Date.now()}`;

return [{
  json: {
    success: true,
    token,
    refreshToken: `refresh_${userId}_${Date.now()}`,
    expiresIn: 86400,
    user: {
      id:     userId,
      name:   name,
      email:  email,
      avatar: null,
      plan:   'free'
    }
  }
}];
